import { useEffect, useRef, useState } from "react";
import { motion, useInView } from "framer-motion";

import { toPriceFormat } from "../../libs/functions";

import { Button } from "@nextui-org/react";

import ButtonAddCart from "../../components/ButtonAddCart";

import { FaRegEye } from "react-icons/fa";

function TablePrices({
  setItemToComparate = () => {},
  tableAriaLabel = "",
  measureFormat = "",
  rows = [],
  cart = {},
  handleAdd = () => {},
}) {
  const ref = useRef(null);
  const isInView = useInView(ref);

  const rowsPerView = 10;
  const [totalVisibleRows, setTotalVisibleRows] = useState(rowsPerView);
  const visibleRows = rows.slice(0, totalVisibleRows);

  const showMore = () => {
    const total_ = totalVisibleRows + rowsPerView;
    setTotalVisibleRows(total_);
  };

  useEffect(() => {
    if (isInView) showMore();
  }, [isInView]);

  return (
    <div
      data-slot="table-container"
      className="w-full overflow-x-auto scrollbar scrollbar-thumb-rounded-full scrollbar-track-rounded-full scrollbar-thumb-custom1 scrollbar-track-custom2-10 scrollbar-w-3 scrollbar-h-3 hover:scrollbar-thumb-custom1-6"
    >
      <table
        aria-label={tableAriaLabel || null}
        className="w-full sm:min-w-[750px] max-w-[900px] text-xl xs:text-2xl font-semibold min-[1100px]:place-self-center table-dinamic max-sm:border-separate border-spacing-y-3"
      >
        <thead className="border-b-3">
          <tr>
            <td className="p-2 border-e-3">
              <p>Medida</p>
              {measureFormat || null}(mm)
            </td>

            <td colSpan={4} className="p-2">
              <p>
                Precio(xU)
                <span className="font-size-secondary">Unidades minimas</span>
              </p>
            </td>
          </tr>
        </thead>

        <tbody>
          {visibleRows?.map((item) => {
            const noStock = item?.noStock || false;
            const inCart = item.id in cart;

            return (
              <motion.tr
                key={item.id}
                className="even:text-custom2-10 dark:even:text-custom1 group hover:text-white"
                variants={{
                  hidden: { opacity: 0 },
                  visible: { opacity: 1 },
                }}
              >
                <td
                  className={`p-2 text-start whitespace-nowrap sm:border-e-3 max-sm:border-3 max-sm:rounded-t-lg group-hover:bg-custom2${
                    inCart ? " bg-success/30" : noStock ? " bg-divider" : ""
                  }`}
                  data-label="medida"
                >
                  <div className="flex gap-2 justify-end items-center w-full sm:flex-row-reverse">
                    <span>{item.label} </span>
                    <Button
                      color="secondary"
                      isIconOnly
                      className="shadow-md"
                      onPress={() => setItemToComparate(item)}
                    >
                      <FaRegEye size={18} />
                    </Button>
                  </div>
                </td>

                {item?.price_data?.prices_qtts &&
                  Object.entries(item.price_data.prices_qtts).map(
                    ([qtt, price]) => {
                      const inCart_qtt =
                        inCart && cart[item.id].qtt === Number(qtt);
                      return (
                        <td
                          key={`precio_x${qtt}`}
                          className={`p-2 hover:!text-custom1-5 max-sm:last:border-b-3 max-sm:border-x-3 last:rounded-b-lg group-hover:bg-custom2${
                            noStock ? " bg-divider" : ""
                          }`}
                        >
                          <div className="flex gap-2 justify-end items-center w-full">
                            <div className="flex items-end justify-center">
                              {toPriceFormat(price)}
                              <span className="font-size-secondary">
                                ({qtt}u)
                              </span>
                            </div>

                            <ButtonAddCart
                              inCart={inCart_qtt}
                              itemData={item}
                              handleAdd={() => {
                                let qtt_ = 0;
                                if (!inCart_qtt) qtt_ = Number(qtt);
                                item.qtt = qtt_;

                                handleAdd(item);
                              }}
                            />
                          </div>
                        </td>
                      );
                    }
                  )}
              </motion.tr>
            );
          })}

          <tr>
            <td className="pt-4">
              {totalVisibleRows < rows.length && (
                <Button
                  ref={ref}
                  size="lg"
                  className="bg-custom1-2 text-custom2--2 font-bold text-xl hover:scale-105"
                  onPress={() => showMore()}
                >
                  +Mas
                </Button>
              )}
            </td>
            <td colSpan={4}></td>
          </tr>
        </tbody>
      </table>
    </div>
  );
}

export default TablePrices;
